import{_ as o,c as a,o as i,a8 as l}from"./chunks/framework.BrmF0WDH.js";const h=JSON.parse('{"title":"06-Runtime渲染与组件机制","description":"","frontmatter":{},"headers":[],"relativePath":"onboarding/06-Runtime渲染与组件机制/index.md","filePath":"onboarding/06-Runtime渲染与组件机制/index.md","lastUpdated":1777649372000}'),t={name:"onboarding/06-Runtime渲染与组件机制/index.md"};function d(n,e,p,r,c,u){return i(),a("div",null,e[0]||(e[0]=[l('<h1 id="_06-runtime渲染与组件机制" tabindex="1">06-Runtime渲染与组件机制 <a class="header-anchor" href="#_06-runtime渲染与组件机制" aria-label="Permalink to &quot;06-Runtime渲染与组件机制&quot;">​</a></h1><h2 id="runtime-的定位" tabindex="1">Runtime 的定位 <a class="header-anchor" href="#runtime-的定位" aria-label="Permalink to &quot;Runtime 的定位&quot;">​</a></h2><p>runtime 是“把当前低代码页面执行出来”的地方。</p><p>它不是编辑器的一部分，而是被 sandbox 托管在 iframe 里的独立运行环境。当前仓库里有两套：</p><ul><li><code>runtime/vue3-active</code></li><li><code>runtime/vue2-active</code></li></ul><p>两套 runtime 提供的接口几乎一致，只是底层框架不同。</p><h2 id="runtime-启动时做了什么" tabindex="1">Runtime 启动时做了什么 <a class="header-anchor" href="#runtime-启动时做了什么" aria-label="Permalink to &quot;Runtime 启动时做了什么&quot;">​</a></h2><p>以 <code>runtime/vue3-active/page/main.ts</code> 为例：</p><ol><li>读取本地或注入的页面配置</li><li>创建 <code>LowCodeRoot</code></li><li>注册组件库里的组件到 <code>app</code></li><li>将 <code>app</code> 注入 Vue 应用</li><li>由 <code>App.vue</code> 渲染当前页面</li></ol><p>这里最重要的是第三步：runtime 先有 <code>LowCodeRoot</code>，再有 Vue 页面壳。</p><h2 id="为什么组件库要注册到-lowcoderoot" tabindex="1">为什么组件库要注册到 <code>LowCodeRoot</code> <a class="header-anchor" href="#为什么组件库要注册到-lowcoderoot" aria-label="Permalink to &quot;为什么组件库要注册到 `LowCodeRoot`&quot;">​</a></h2><p>因为真正渲染动态组件的是：</p><p><code>packages/ui/src/q-component/src/component.vue</code></p><p>它不是写死组件名，而是：</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">app.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveComponent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(props.config.component </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">||</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> props.config.type)</span></span></code></pre></div><p>也就是说，runtime 组件解析权不在 Vue 模板里，而在 <code>LowCodeRoot.components</code> 这个注册表里。</p><p>这也是项目具备扩展性的关键点之一。</p><h2 id="ui-组件层到底做了什么" tabindex="1">UI 组件层到底做了什么 <a class="header-anchor" href="#ui-组件层到底做了什么" aria-label="Permalink to &quot;UI 组件层到底做了什么&quot;">​</a></h2><p><code>packages/ui</code> 里的组件可以分成两类：</p><h3 id="_1-运行时渲染组件" tabindex="1">1. 运行时渲染组件 <a class="header-anchor" href="#_1-运行时渲染组件" aria-label="Permalink to &quot;1. 运行时渲染组件&quot;">​</a></h3><p>例如：</p><ul><li><code>Page</code></li><li><code>Container</code></li><li><code>Button</code></li><li><code>Text</code></li><li><code>Img</code></li><li><code>Video</code></li></ul><p>这类组件负责真的渲染页面。</p><h3 id="_2-编辑器元数据" tabindex="1">2. 编辑器元数据 <a class="header-anchor" href="#_2-编辑器元数据" aria-label="Permalink to &quot;2. 编辑器元数据&quot;">​</a></h3><p>例如：</p><ul><li><code>formSchema.ts</code></li><li><code>event.ts</code></li></ul><p>这类文件告诉编辑器：</p><ul><li>该组件有哪些可配置项</li><li>哪些事件可以被可视化配置</li></ul><p>这两个层面共同组成了“组件协议”。</p><h2 id="useapp-是连接-core-和-vue-的关键钩子" tabindex="1"><code>useApp</code> 是连接 Core 和 Vue 的关键钩子 <a class="header-anchor" href="#useapp-是连接-core-和-vue-的关键钩子" aria-label="Permalink to &quot;`useApp` 是连接 Core 和 Vue 的关键钩子&quot;">​</a></h2><p><code>packages/ui/src/hooks/use-app.ts</code> 做了三件事：</p><ol><li>注入 <code>app</code></li><li>通过 <code>field</code> 拿到对应 <code>LowCodeNode</code></li><li>在 created/mounted/unmounted 时触发节点生命周期</li></ol><p>所以一个 runtime 组件挂载时，同时完成了两件事：</p><ul><li>Vue 组件自己完成挂载</li><li>LowCode 节点完成生命周期执行</li></ul><p>这就是为什么 <code>Core</code> 和 Vue 运行时能被接起来。</p><h2 id="页面为什么能-按当前页切换" tabindex="1">页面为什么能“按当前页切换” <a class="header-anchor" href="#页面为什么能-按当前页切换" aria-label="Permalink to &quot;页面为什么能“按当前页切换”&quot;">​</a></h2><p>runtime playground App 会暴露：</p><ul><li><code>updateRootConfig</code></li><li><code>updatePageField</code></li></ul><p>其中：</p><ul><li><code>updateRootConfig</code> 更新整棵 root，并同步 <code>app.setConfig(...)</code></li><li><code>updatePageField</code> 切换当前页，并同步 <code>app.setPage(...)</code></li></ul><p>所以切页不是在编辑器里直接切 DOM，而是切 runtime 当前激活的 page 节点。</p><h2 id="编辑态-runtime-和预览-runtime-的区别" tabindex="1">编辑态 runtime 和预览 runtime 的区别 <a class="header-anchor" href="#编辑态-runtime-和预览-runtime-的区别" aria-label="Permalink to &quot;编辑态 runtime 和预览 runtime 的区别&quot;">​</a></h2><p>仓库里你会看到两个场景：</p><h3 id="playground" tabindex="1"><code>playground</code> <a class="header-anchor" href="#playground" aria-label="Permalink to &quot;`playground`&quot;">​</a></h3><p>这是编辑态 runtime，提供 <code>select / add / update / delete</code> 等接口给 sandbox 使用。</p><h3 id="page" tabindex="1"><code>page</code> <a class="header-anchor" href="#page" aria-label="Permalink to &quot;`page`&quot;">​</a></h3><p>这是面向预览或真实页面渲染的 runtime，更接近最终运行态。</p><p>这两者共用同一套 <code>Core + UI</code> 能力，但一个偏编辑，一个偏展示。</p><h2 id="组件系统为什么可扩展" tabindex="1">组件系统为什么可扩展 <a class="header-anchor" href="#组件系统为什么可扩展" aria-label="Permalink to &quot;组件系统为什么可扩展&quot;">​</a></h2><p>因为一个组件要接入这套系统，通常只需要补齐三类东西：</p><ol><li>真正的运行时 Vue 组件</li><li>对应的 <code>formSchema.ts</code></li><li>可选的 <code>event.ts</code></li></ol><p>然后把它注册进组件导出和配置映射里。</p><p>这意味着：</p><ul><li>组件渲染能力</li><li>编辑器属性面板</li><li>事件可视化配置</li></ul><p>三件事是配套扩展的。</p><h2 id="这一层的关键认知" tabindex="1">这一层的关键认知 <a class="header-anchor" href="#这一层的关键认知" aria-label="Permalink to &quot;这一层的关键认知&quot;">​</a></h2><p>项目不是“编辑器调用一堆业务组件”，而是“runtime 在执行一份组件协议”。</p><p>这份协议至少包括：</p><ul><li>节点类型和字段</li><li>组件解析名</li><li>组件属性</li><li>生命周期</li><li>事件清单</li><li>属性面板元数据</li></ul><p>理解成协议层后，你再看跨框架、跨项目复用，就会自然很多。</p>',60)]))}const m=o(t,[["render",d]]);export{h as __pageData,m as default};
